$sourceHash=(Get-FileHash $source -Algorithm SHA256).Hash.ToUpperInvariant();$leaderHash=(Get-FileHash $leader -Algorithm SHA256).Hash.ToUpperInvariant();if($sourceHash-ne$expectedSourceHash){throw 'Research source changed.'};if($leaderHash-ne$expectedLeaderHash){throw 'Leader profile changed.'}
$base=Get-SourceInputs $source;if($base.Count-ne247){throw "Expected 247 source inputs, found $($base.Count)."};$leaderCount=0
