Set-FixedInput $base 'InpEvidenceSourceHash' $sourceHash -StringValue;Set-FixedInput $base 'InpEvidenceRunLabel' 'four_lane_m15_squeeze_target_interaction_discovery_model1' -StringValue;Set-FixedInput $base 'InpLogTrades' 'false';Set-FixedInput $base 'InpShowDashboard' 'false'
