$stopRule='Discovery only. Both disabled controls and the enabled 1.50R reference must exactly reproduce their prior identities. Fixed 2.00R center must be profitable and no worse than leader control in each disjoint era, improve continuous net >=10% and CAGR >=0.20 point, retain PF >=98% of control, recovery and return/drawdown >=control, keep DD <=1.30% and <=control+0.15 point, and retain >=300 trades. At least one 1.75R or 2.25R neighbor must be no worse than control in both eras, improve net >=8% and CAGR >=0.15 point, retain PF/recovery/return-DD >=98% of control, meet the same DD and activity limits, and differ from the 1.50R reference. No alternate target selection or threshold rescue after observation.'
$package=Resolve-RepoPath $PackageDir;Clear-OutputDirSafe $package;$configDir=Join-Path $package 'configs';$profileDir=Join-Path $package 'profiles';$reportDir=Join-Path $package 'reports_here';$sourceDir=Join-Path $package 'source';New-Item -ItemType Directory -Path $configDir,$profileDir,$reportDir,$sourceDir -Force|Out-Null;Copy-Item $source (Join-Path $sourceDir 'Professional_XAUUSD_EA.mq5') -Force
$rows=[Collections.Generic.List[object]]::new();$ordinal=0;$candidateRank=0
foreach($variant in $variants){$candidateRank++;$inputs=Copy-Inputs $base;Set-FixedInput $inputs 'InpSQEnabled' $variant.Enabled;Set-FixedInput $inputs 'InpSQRiskPercent' '0.10';Set-FixedInput $inputs 'InpSQTakeProfitR' $variant.Target;Set-FixedInput $inputs 'InpMaximumAccountPositions' $variant.Positions;$profilePath=Join-Path $profileDir "$($variant.Name).set";@($inputs.Keys|Sort-Object|ForEach-Object{$inputs[$_]})|Set-Content $profilePath -Encoding ASCII;$profileHash=(Get-FileHash $profilePath -Algorithm SHA256).Hash.ToUpperInvariant();foreach($window in $windows){$ordinal++;$configName='{0:000}_{1}_{2}_m1.ini'-f$ordinal,$variant.Name,$window.Name;$configPath=Join-Path $configDir $configName;$reportName="$($variant.Name)_$($window.Name)_m1";Write-SeasonalTesterConfig -Path $configPath -ReportRoot $reportDir -ReportName $reportName -From $window.From -To $window.To -Inputs $inputs -Model 1 -Deposit 10000 -Period 15;$rows.Add([pscustomobject][ordered]@{QueueRank=$ordinal;Candidate=$variant.Name;CandidateRank=$candidateRank;Role=$variant.Role;Phase='four_lane_m15_squeeze_target_interaction_discovery_model1';Window=$window.Name;From=$window.From;To=$window.To;Model=1;Deposit=10000;FeatureEnabled=$variant.Enabled;MaximumAccountPositions=$variant.Positions;SqueezeRiskPercent='0.10';SqueezeTakeProfitR=$variant.Target;BreakoutLookbackBars='8';MaximumHoldBars='32';MaximumPortfolioOpenRiskPercent='0.75';ExpectedReportName=$reportName;PackageConfig="$PackageDir\configs\$configName";ReportDestination="$PackageDir\reports_here\$reportName";ConfigSha256=(Get-FileHash $configPath -Algorithm SHA256).Hash.ToUpperInvariant();ProfileSha256=$profileHash;SourceSha256=$sourceHash;StopRule=$stopRule})|Out-Null}}
